INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00939', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '適齡國民依強迫入學條例第12條或第13條規定經核定暫緩入學或因其他原因未能適時入學，於其原因 消滅申請入學時，未滿15歲者，得由學校以何種方式編入於適當年級就讀？', '["學校可以經校務會議安置", "學校可以經甄試編入", "學校可以經特殊教育委員會安置", "學校可以經抽籤編入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00940', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依照偏遠地區學校教育發展條例的規定，對於偏遠地區教師的甄選下列敘述何者錯誤？', '["專聘教師聘期一次最長 2 年；其表現優良，經教師評審委員會審核且報主管機關同意者，由學校校長 再聘之", "專為偏遠地區學校辦理之甄選，聘任之教師應實際服務 6 年以上，始得提出申請介聘至非偏遠地區學 校服務", "專聘教師連續任滿6年，且依該條例第7條第2項取得第二專長，表現優良者，得一次再聘6年或依 其意願參加專任教師甄選，並予以加分優待", "偏遠地區國民小學全校學生人數未滿50人且採混齡編班者，除置校長及必要之行政人力外，其教師員 額編制，得以生師比四比一計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00941', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依高級中等教育法規定，提供包括基本學科、專業及實習學科課程，以輔導學生選修適性課程之學校屬 於那一類型？', '["普通型高級中等學校", "技術型高級中等學校", "專業型高級中等學校", "綜合型高級中等學校"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00942', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '為提昇全民藝術涵養、美感素養，實施藝術教育，我國訂有藝術教育法。請問下列敘述何者錯誤？', '["藝術教育主要類別可分為：表演藝術、視覺藝術、音像藝術、藝術行政及其他有關之藝術與美感教育", "藝術教育實施上可分為：專業藝術教育、普通藝術教育及社會藝術教育", "高級中等以下學校，經報請核准後得設立藝術才能班，就學生之能力、性向及興趣輔導其適當發展", "學校應宣導並落實相關之專利權、商標權、著作權或其他智慧財產權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00943', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依據幼兒教育與照顧法之規定，下列敘述何者錯誤？', '["幼兒定義為2歲以上到就讀國民小學前之人", "未滿3歲幼兒每班以16人為限，且不得與其他年齡幼兒混齡", "教保服務人員有體罰情狀者，處新臺幣6千元以上3萬元以下罰鍰", "機構違反本法規定者，主管機關可處以罰鍰、減招、停止招生、停辦或廢止設立許可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00944', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '生涯規劃相關科目需列為高級中等以下學校師資職前教育課程之必修學分，此項規定明定於下列何項法令？', '["學生輔導法", "師資培育法", "技術及職業教育法", "大學設立師資培育中心辦法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00945', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '為保障學生學習權及教師工作權，根據高級中等以下學校教師專業審查會組成及運作辦法，請問下列敘 述何者錯誤？', '["該辦法的法源依據為教師法", "教師專業審查會置委員11人至19人，任期3年", "教師專業審查會任一性別委員人數不得少於委員總數三分之一", "涉及性別平等、體罰霸凌等事件時，教師會代表應少於委員總數二分之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00946', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關教師法當中所規範的教師聘任、解聘、不續聘及資遣等內容，下列敘述何者錯誤？', '["取得教師資格有兩種管道：高級中等以下學校之採檢定制；專科以上學校採審定制", "教師評審委員會調查性平、體罰、霸凌等事件時，應納入學者專家代表至少三分之一", "高級中等以下學校教師有教學不力或不能勝任工作有具體事實者，由學校向主管機關申請教師專業審 查委員會調查", "經相關委員會調查確認有性侵害行為屬實，應予解聘，且終身不得聘任為教師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00947', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依公立高級中等以下學校委託私人辦理實驗教育條例規定，下列申請與審查程序何者錯誤？', '["各該主管機關就學校委託私人辦理，應先邀請學者、專家、地方社區人士、家長或相關人士進行專案 評估，並舉行公聽會", "專案評估通過後，各該主管機關應公告委託資格、期間、權利義務、評選基準、申請期限及決定程序 等相關資訊，受理申請", "申請人所提經營計畫，各該主管機關應送請相關學者專家初審，並依學校屬直轄市、縣（市）立或國 立，分別經直轄市、縣（市）教育審議委員會或中央主管機關所組學校委託私人辦理審議會複審", "申請人應自收受核准委託辦理通知之次日起2個月內，與各該主管機關簽訂行政契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00948', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-110-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '為促進與維護學生身心健康及全人發展，我國學生輔導法於民國103年11月正式公布施行，下列敘述何 者正確？', '["國民中學專任輔導教師員額編制，12班以下者，置1人，13班以上者，每12班增置1人", "專科以上學校學生1,500人以下者，應置專業輔導人員至少1人；超過1,500人，增置1人", "穩定性學校應視學生身心狀況及需求，提供一般性輔導、個別性輔導或處遇性輔導之三級輔導", "高級中等以下學校主管機關應定期辦理初任輔導主任或組長、輔導教師及初聘專業輔導人員至少40小 時之職前基礎培訓課程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:42+00:00", "source_pdf_sha1": "f5b0d27260af", "answer_pdf_sha1": "9007eb09ac41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "504", "s": "0401", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
